<?php
namespace App\Domain\Loans\Actions;
use App\Enums\LoanApplicationStatus;use App\Models\LoanApplication;use Illuminate\Validation\ValidationException;
class SubmitLoanApplication{public function execute(LoanApplication $application):LoanApplication{$application->loadMissing(['product','workflow.steps','guarantors']);$assessment=$application->assessments()->latest('assessed_at')->first();if(!$assessment||!$assessment->eligibility_result['eligible']||!$assessment->policy_result['eligible'])throw ValidationException::withMessages(['application'=>['A passing assessment is required before submission.']]);if($application->product->requires_guarantors&&$application->guarantors->where('status','accepted')->count()<$application->product->minimum_guarantors)throw ValidationException::withMessages(['guarantors'=>['The required guarantors have not accepted.']]);$first=$application->workflow?->steps->first(fn($step)=>(!$step->minimum_amount_minor||$application->requested_principal_minor>=$step->minimum_amount_minor)&&(!$step->maximum_amount_minor||$application->requested_principal_minor<=$step->maximum_amount_minor));if(!$first)throw ValidationException::withMessages(['approval_workflow_id'=>['An applicable approval workflow step is required.']]);$application->update(['status'=>LoanApplicationStatus::Submitted,'submitted_at'=>now(),'current_approval_sequence'=>$first->sequence]);return $application->refresh();}}
